import React, { useState } from "react";
import "../styles/Contact.css";

const Contact = () => {
  const [formData, setFormData] = useState({
    fullName: '',
    email: '',
    phoneNumber: '',
    subject: '',
    message: ''
  });
  const [submissionStatus, setSubmissionStatus] = useState(null);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    try {
      const response = await fetch('https://your-api-url/api/contact/submit', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          FullName: formData.fullName,
          Email: formData.email,
          PhoneNumber: formData.phoneNumber,
          Subject: formData.subject,
          Message: formData.message
        }),
      });
      
      if (response.ok) {
        setSubmissionStatus('success');
        setFormData({
          fullName: '',
          email: '',
          phoneNumber: '',
          subject: '',
          message: ''
        });
      } else {
        setSubmissionStatus('error');
      }
    } catch (error) {
      setSubmissionStatus('error');
      console.error('Error submitting form:', error);
    }
  };

  return (
    <div id="contact" className="contact-container">
      <h1>CONTACT US</h1>

      {/* Google Maps Section */}
      <div className="map-container">
        <iframe
          title="Google Map"
          className="google-map"
          src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3048.146201882546!2d44.62674911141569!3d40.18355967135914!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x406aa5fb2d2aeb97%3A0x7a90e13129b8e750!2z1Y7VuNaC1aTVvSDUv9Wl1bbVv9aA1bjVtg!5e0!3m2!1shy!2sam!4v1743157411782!5m2!1shy!2sam"
          allowFullScreen
          loading="lazy"
          referrerPolicy="no-referrer-when-downgrade"
        ></iframe>
      </div>

      <div className="contact-content">
        <div className="contact-info">
          <h2>Law Office</h2>
          <div className="info-item">
            <span className="icon">📍</span>
            <div>
              <h3>Address</h3>
              <p>Armenia,Yerevan City</p>
              <p>Woods Centre</p>
            </div>
          </div>
          <div className="info-item">
            <span className="icon">📞</span>
            <div>
              <h3>Phone</h3>
              <p>+374 12 34 56 78 </p>
            </div>
          </div>
          <div className="info-item">
            <span className="icon">📧</span>
            <div>
              <h3>E-mail</h3>
              <p>info@law.com</p>
            </div>
          </div>
        </div>

        <div className="contact-form">
          <h3>LEAVE US A MESSAGE</h3>
          {submissionStatus === 'success' && (
            <div className="success-message">
              Thank you for your submission! We'll get back to you soon.
            </div>
          )}
          {submissionStatus === 'error' && (
            <div className="error-message">
              There was an error submitting your form. Please try again.
            </div>
          )}
          <form onSubmit={handleSubmit}>
            <input 
              type="text" 
              name="fullName"
              placeholder="Your Full Name" 
              value={formData.fullName}
              onChange={handleChange}
              required 
            />
            <input 
              type="email" 
              name="email"
              placeholder="example@email.com" 
              value={formData.email}
              onChange={handleChange}
              required 
            />
            <input 
              type="text" 
              name="phoneNumber"
              placeholder="012 34 56 78" 
              value={formData.phoneNumber}
              onChange={handleChange}
              required 
            />
            <input 
              type="text" 
              name="subject"
              placeholder="Subject" 
              value={formData.subject}
              onChange={handleChange}
              required 
            />
            <textarea 
              name="message"
              placeholder="Write your message here..." 
              value={formData.message}
              onChange={handleChange}
              required
            ></textarea>
            
            <button type="submit">Submit</button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default Contact;
